package ch.usi.inf.examples.microbatch_dp.common.api;

import ch.usi.inf.confidentialstorm.common.crypto.exception.EnclaveServiceException;
import ch.usi.inf.examples.microbatch_dp.common.api.model.MicroBatchEncryptedRecord;
import org.apache.teaclave.javasdk.common.annotations.EnclaveService;

/**
 * Enclave-side service that encrypts synthetic records generated by the host spout.
 * Encryption (and routing AAD) happens inside the enclave; host only handles ciphertext.
 */
@EnclaveService
public interface MicroBatchDataService {
    MicroBatchEncryptedRecord encryptRecord(String key, String count, String userId) throws EnclaveServiceException;
}
